mapper.select:
select document_attachment_id, company_id, document_id, file_url, file_name, file_type, file_size_bytes,
       media_kind, status, uploaded_by, uploaded_at
from document_attachments
where company_id = #{companyId,jdbcType=VARCHAR}
  and document_id = #{documentId,jdbcType=VARCHAR}
  and upper(coalesce(trim(status), '')) = 'ACTIVE'
order by uploaded_at desc
limit #{limit,jdbcType=INTEGER}
